"use client";

import { useRouter } from "next/navigation";
import { useEffect } from "react";

import { useAuth } from "@/hooks/use-auth";

export function RequireAuth({ children }: { children: React.ReactNode }) {
  const { loading, user } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (!loading && !user) {
      router.replace("/login");
    }
  }, [loading, router, user]);

  if (loading || !user) {
    return (
      <div className="flex min-h-screen items-center justify-center text-sm text-zinc-500">
        Loading your hot dog ledger...
      </div>
    );
  }

  return <>{children}</>;
}

"use client";

import {
  Line,
  LineChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from "recharts";

import type { ChartPoint } from "@/types/models";

type Props = {
  data: ChartPoint[];
};

export function CumulativeChart({ data }: Props) {
  if (!data.length) {
    return <p className="text-sm text-zinc-500">No dogs logged yet this year. Go set the pace.</p>;
  }

  return (
    <div className="h-56 min-h-56 w-full min-w-0">
      <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={220}>
        <LineChart data={data} margin={{ top: 8, right: 8, left: -20, bottom: 8 }}>
          <XAxis dataKey="dateLabel" tickLine={false} axisLine={false} minTickGap={28} />
          <YAxis allowDecimals={false} tickLine={false} axisLine={false} />
          <Tooltip contentStyle={{ borderRadius: 12, border: "1px solid #27272a" }} />
          <Line type="monotone" dataKey="total" stroke="#f59e0b" strokeWidth={3} dot={false} />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

import Image from "next/image";

import { formatReadableDateTime } from "@/lib/utils/dates";
import type { DogLog } from "@/types/models";

type Props = {
  logs: DogLog[];
};

export function RecentLogs({ logs }: Props) {
  if (!logs.length) {
    return <p className="text-sm text-zinc-500">No entries yet. Tap I ate a dog to start the year strong.</p>;
  }

  return (
    <ul className="space-y-3">
      {logs.map((log) => (
        <li key={log.id} className="flex items-center gap-3 rounded-xl border border-zinc-200 p-2 dark:border-zinc-800">
          <div className="relative h-14 w-14 shrink-0 overflow-hidden rounded-lg">
            <Image src={log.imageUrl} alt="Hot dog proof" fill sizes="56px" className="object-cover" />
          </div>
          <div className="min-w-0 flex-1">
            <p className="text-sm font-medium text-zinc-900 dark:text-zinc-50">+{log.quantity} dog{log.quantity > 1 ? "s" : ""}</p>
            <p className="truncate text-xs text-zinc-500">{formatReadableDateTime(log.loggedAt.toDate())}</p>
          </div>
        </li>
      ))}
    </ul>
  );
}

