"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Home, PlusCircle, Trophy, UserCircle2 } from "lucide-react";
import { clsx } from "clsx";

const items = [
  { href: "/dashboard", label: "Home", icon: Home },
  { href: "/log", label: "Log", icon: PlusCircle },
  { href: "/leaderboard", label: "Board", icon: Trophy },
  { href: "/profile", label: "You", icon: UserCircle2 },
];

export function BottomNav() {
  const pathname = usePathname();

  return (
    <nav
      className="fixed inset-x-0 bottom-0 z-30 border-t border-zinc-200 bg-white/95 px-3 pb-[max(env(safe-area-inset-bottom),0.5rem)] pt-2 backdrop-blur dark:border-zinc-800 dark:bg-zinc-950/95"
      aria-label="Primary"
    >
      <ul className="mx-auto grid max-w-xl grid-cols-4 gap-2">
        {items.map(({ href, icon: Icon, label }) => {
          const active = pathname === href;
          return (
            <li key={href}>
              <Link
                href={href}
                className={clsx(
                  "flex min-h-12 flex-col items-center justify-center rounded-xl text-xs font-medium",
                  active
                    ? "bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-200"
                    : "text-zinc-500 dark:text-zinc-400",
                )}
              >
                <Icon size={18} aria-hidden="true" />
                <span>{label}</span>
              </Link>
            </li>
          );
        })}
      </ul>
    </nav>
  );
}

import { clsx } from "clsx";

import type { YearlyTotal } from "@/types/models";

type Props = {
  items: YearlyTotal[];
  currentUserId?: string;
};

export function LeaderboardList({ items, currentUserId }: Props) {
  if (!items.length) {
    return <p className="text-sm text-zinc-500">No leaderboard entries yet. Be the inaugural legend.</p>;
  }

  return (
    <ol className="space-y-2">
      {items.map((entry, index) => {
        const isCurrent = entry.userId === currentUserId;
        return (
          <li
            key={entry.id}
            className={clsx(
              "flex items-center justify-between rounded-xl border px-3 py-2.5",
              isCurrent
                ? "border-amber-400 bg-amber-50 dark:border-amber-400 dark:bg-amber-950/30"
                : "border-zinc-200 dark:border-zinc-800",
            )}
          >
            <div className="flex min-w-0 items-center gap-2.5">
              <span className="w-8 text-sm font-bold text-zinc-500">#{index + 1}</span>
              <div className="min-w-0">
                <p className="truncate text-sm font-semibold text-zinc-900 dark:text-zinc-50">{entry.displayName}</p>
                {isCurrent ? <p className="text-xs text-amber-700 dark:text-amber-200">You</p> : null}
              </div>
            </div>
            <p className="pl-2 text-base font-black text-zinc-900 dark:text-zinc-50 sm:text-lg">{entry.total}</p>
          </li>
        );
      })}
    </ol>
  );
}

"use client";

import Image from "next/image";
import { useEffect, useMemo, useRef } from "react";

import { Button } from "@/components/ui/button";

type Props = {
  file: File | null;
  onFileChange: (file: File | null) => void;
};

export function ImageUploader({ file, onFileChange }: Props) {
  const inputRef = useRef<HTMLInputElement | null>(null);
  const previewUrl = useMemo(() => (file ? URL.createObjectURL(file) : null), [file]);

  function openPicker() {
    const input = inputRef.current;
    if (!input) {
      return;
    }

    if (typeof input.showPicker === "function") {
      input.showPicker();
      return;
    }

    input.click();
  }

  function handleChange(event: React.ChangeEvent<HTMLInputElement>) {
    const selected = event.target.files?.[0] ?? null;
    onFileChange(selected);
    // Allow selecting the same file again after cancel/retry.
    event.target.value = "";
  }

  useEffect(() => {
    return () => {
      if (previewUrl) {
        URL.revokeObjectURL(previewUrl);
      }
    };
  }, [previewUrl]);

  return (
    <div className="space-y-3">
      <input
        ref={inputRef}
        id="photo"
        name="photo"
        type="file"
        accept="image/*"
        className="hidden"
        onChange={handleChange}
      />
      <Button type="button" className="w-full" onClick={openPicker} aria-label="Upload photo proof">
        {file ? "Change proof photo" : "Upload proof photo"}
      </Button>
      {previewUrl ? (
        <div className="relative aspect-[4/3] overflow-hidden rounded-xl border border-zinc-200 dark:border-zinc-800">
          <Image
            src={previewUrl}
            alt="Selected hot dog proof photo preview"
            fill
            sizes="(max-width: 640px) 100vw, 640px"
            className="object-cover"
          />
        </div>
      ) : (
        <p className="text-xs text-zinc-500">Photo proof is required for each log entry.</p>
      )}
    </div>
  );
}

