"use client";

import { useContext } from "react";

import { AuthContext } from "@/components/providers/auth-provider";

export function useAuth() {
  const value = useContext(AuthContext);
  if (!value) {
    throw new Error("useAuth must be used within AuthProvider");
  }
  return value;
}

// Reserved for future server-side Firebase Admin integrations.
// Keep secrets server-side only when this file is implemented.
export {};

import {
  GoogleAuthProvider,
  createUserWithEmailAndPassword,
  signInWithEmailAndPassword,
  signInWithPopup,
  signOut,
} from "firebase/auth";

import { auth } from "@/lib/firebase/client";

const googleProvider = new GoogleAuthProvider();

export async function signInWithGoogle() {
  return signInWithPopup(auth, googleProvider);
}

export async function signInWithEmail(email: string, password: string) {
  return signInWithEmailAndPassword(auth, email, password);
}

export async function signUpWithEmail(email: string, password: string) {
  return createUserWithEmailAndPassword(auth, email, password);
}

export async function signOutUser() {
  return signOut(auth);
}

import { deleteObject, getDownloadURL, ref, uploadBytes } from "firebase/storage";

import { storage } from "@/lib/firebase/client";
import { compressImage } from "@/lib/utils/image";

export type UploadedPhoto = {
  imageUrl: string;
  imagePath: string;
};

export async function uploadDogPhoto(
  userId: string,
  year: number,
  logId: string,
  file: File,
): Promise<UploadedPhoto> {
  const imageBlob = await compressImage(file);
  const imagePath = `dog-photos/${userId}/${year}/${logId}.jpg`;
  const storageRef = ref(storage, imagePath);

  await uploadBytes(storageRef, imageBlob, {
    contentType: "image/jpeg",
    customMetadata: {
      ownerUid: userId,
    },
  });

  const imageUrl = await getDownloadURL(storageRef);
  return { imagePath, imageUrl };
}

export async function deleteDogPhoto(imagePath: string): Promise<void> {
  await deleteObject(ref(storage, imagePath));
}

import { format } from "date-fns";

import { DogLog, ChartPoint } from "@/types/models";

export function buildCumulativeChart(logs: DogLog[]): ChartPoint[] {
  const asc = [...logs].sort(
    (a, b) => a.loggedAt.toDate().getTime() - b.loggedAt.toDate().getTime(),
  );

  let running = 0;
  return asc.map((log) => {
    running += log.quantity;
    return {
      dateLabel: format(log.loggedAt.toDate(), "MMM d"),
      total: running,
    };
  });
}

import { endOfYear, format, startOfYear } from "date-fns";

export function getCurrentYear(): number {
  return new Date().getFullYear();
}

export function yearDateRange(year: number): { start: Date; end: Date } {
  const anchor = new Date(year, 0, 1);
  return { start: startOfYear(anchor), end: endOfYear(anchor) };
}

export function formatShortDate(date: Date): string {
  return format(date, "MMM d");
}

export function formatReadableDateTime(date: Date): string {
  return format(date, "MMM d, yyyy p");
}

import { doc } from "firebase/firestore";

import { db } from "@/lib/firebase/client";
import { createLogAndUpdateTotals } from "@/lib/firebase/firestore";
import { deleteDogPhoto, uploadDogPhoto } from "@/lib/firebase/storage";
import type { LogInput } from "@/types/models";

export async function submitDogLog(args: {
  userId: string;
  displayName: string;
  input: LogInput;
  photoFile: File;
}): Promise<void> {
  const logRef = doc(db, "dog_logs", crypto.randomUUID());
  const year = args.input.loggedAt.getFullYear();

  let imagePath = "";

  try {
    const uploaded = await uploadDogPhoto(args.userId, year, logRef.id, args.photoFile);
    imagePath = uploaded.imagePath;

    await createLogAndUpdateTotals({
      userId: args.userId,
      displayName: args.displayName,
      logId: logRef.id,
      imagePath: uploaded.imagePath,
      imageUrl: uploaded.imageUrl,
      input: args.input,
    });
  } catch (error) {
    if (imagePath) {
      await deleteDogPhoto(imagePath).catch(() => undefined);
    }
    throw error;
  }
}

import { Timestamp } from "firebase/firestore";

export type Nullable<T> = T | null;

export type UserProfile = {
  uid: string;
  displayName: string;
  email: string;
  photoURL: Nullable<string>;
  createdAt: Timestamp;
  lastActiveAt: Timestamp;
  currentYearTotal: number;
  currentYear: number;
};

export type DogLog = {
  id: string;
  userId: string;
  displayName: string;
  quantity: number;
  imageUrl: string;
  imagePath: string;
  note: Nullable<string>;
  loggedAt: Timestamp;
  year: number;
  createdAt: Timestamp;
};

export type YearlyTotal = {
  id: string;
  year: number;
  userId: string;
  displayName: string;
  total: number;
  mostRecentLoggedAt: Timestamp;
  updatedAt: Timestamp;
};

export type LogInput = {
  quantity: number;
  note: string;
  loggedAt: Date;
};

export type ChartPoint = {
  dateLabel: string;
  total: number;
};

rules_version = '2';
service firebase.storage {
  match /b/{bucket}/o {
    match /dog-photos/{userId}/{year}/{fileName} {
      allow read: if request.auth != null;
      allow write: if request.auth != null
        && request.auth.uid == userId
        && request.resource.size < 8 * 1024 * 1024
        && request.resource.contentType.matches('image/.*');
    }
  }
}
